// Extract From and To emails from Gmail headers
const headers = $json.payload.headers;

const extractEmail = (headerName) => {
  const header = headers.find(h => h.name === headerName);
  if (!header) return null;
  const match = header.value.match(/<(.+?)>/);
  return match ? match[1].toLowerCase().trim() : header.value.toLowerCase().trim();
};

const fromEmail = extractEmail('From');
const toEmail = extractEmail('To');
const subject = headers.find(h => h.name === 'Subject')?.value || '(No subject)';

// Get from name
const fromHeader = headers.find(h => h.name === 'From')?.value || '';
const fromName = fromHeader.includes('<') ? fromHeader.split('<')[0].trim() : fromEmail;

return {
  json: {
    from_email: fromEmail,
    to_email: toEmail,
    from_name: fromName,
    subject: subject,
    thread_id: $json.threadId,
    message_id: $json.id,
    snippet: $json.snippet,
    received_at: new Date(parseInt($json.internalDate)).toISOString(),
    gmail_payload: $json.payload
  }
};

// Merge email data with match result
const emailData = items[0].json; // From "Extract Email Data"
const matchResult = items[1].json; // From "Match Email (Supabase RPC)"

return {
  json: {
    ...emailData,
    match: matchResult
  }
};

