// Parse AI response and prepare for DB insert
const aiResponse = $json.message?.content || $json.choices?.[0]?.message?.content || '';

let aiData;
try {
  // Remove markdown code blocks if present
  const cleaned = aiResponse.replace(/```json\n?/g, '').replace(/```\n?/g, '');
  aiData = JSON.parse(cleaned);
} catch (e) {
  // Fallback if parsing fails
  aiData = {
    summary: $json.snippet || 'Error parsing AI response',
    sentiment: 'neutral',
    key_topics: [],
    action_items: [],
    needs_response: false,
    priority: 'normal',
    extracted_data: {}
  };
}

return {
  json: {
    thread_id: items[0].json.thread_id,
    type: items[0].json.match.type,
    entity_id: items[0].json.match.entity_id,
    direction: items[0].json.match.direction,
    subject: items[0].json.subject,
    from_email: items[0].json.from_email,
    from_name: items[0].json.from_name,
    to_email: items[0].json.to_email,
    last_message: items[0].json.snippet,
    last_received_at: items[0].json.received_at,
    summary: aiData.summary,
    sentiment: aiData.sentiment,
    key_topics: JSON.stringify(aiData.key_topics),
    action_items: JSON.stringify(aiData.action_items),
    extracted_data: JSON.stringify(aiData.extracted_data),
    needs_response: aiData.needs_response,
    priority: aiData.priority
  }
};

